import React, { useEffect, useState } from "react";
import { Namedb } from "../components/firebase_setup";
//import { v4 } from "uuid";
import { collection, getDocs } from "firebase/firestore";
import { useNavigate } from "react-router-dom";


function Feed() {
  console.log("This is the feed");
  const navigate = useNavigate();

  const [pdata, setPData] = useState([]);  //state to hold profile data, its a map

  const handleLogout = () => {
    localStorage.clear();
    navigate("/");
  };

  const getData = async() => {
    const dataref = collection(Namedb, "ProfileData");  //References to the Collection "ProfileData" in Collection
    const profileDb = await getDocs(dataref);           //Retrives the data from "P"
    const retrivePData = profileDb.docs.map(val=>({...val.data(), id:val.id}));
    setPData(retrivePData);
  }

  useEffect(()=>{
    getData()
  })
  console.log(pdata,"firedataP");

  return (
    <div className="Feed">
        <h1>This would be the main feed page
            Hopefully you get to see post, comment and like things
        </h1>
        <div>
            {
                pdata.map(value => <div>
                    <p> Profile Name: {value.txtval}</p><br/><br/>
                    <p> Profile Pic </p>
                    <img src={value.imgUrl}/>
                </div>)
            }
        </div>
        <button className="Logoutbut" onClick={handleLogout}>Logout</button>
    </div>

    
  );
}

export default Feed;
